# --- Session Management ---

SESSION_PREFIX = "session:"
SESSION_TTL = 3600  # 1 hour
SESSION_COOKIE_NAME = "session_id"


def generate_session_id():
    """Generate a cryptographically secure session ID."""
    return secrets.token_urlsafe(48)


def get_session_key(session_id):
    """Create a namespaced Redis key for the session."""
    return f"{SESSION_PREFIX}{session_id}"


def create_session(user_data):
    """Create a new session in Redis and return the session ID."""
    session_id = generate_session_id()
    session_key = get_session_key(session_id)
    session_data = {
        "user_data": json.dumps(user_data),
        "created_at": datetime.utcnow().isoformat(),
        "last_accessed": datetime.utcnow().isoformat(),
    }
    # Use a pipeline for atomic SET + EXPIRE
    pipe = redis_client.pipeline(transaction=True)
    pipe.hset(session_key, mapping=session_data)
    pipe.expire(session_key, SESSION_TTL)
    pipe.execute()
    return session_id


def get_session(session_id):
    """Retrieve session data from Redis."""
    if not session_id:
        return None
    session_key = get_session_key(session_id)
    session_data = redis_client.hgetall(session_key)
    if not session_data:
        return None
    # Refresh TTL on access (sliding expiration)
    pipe = redis_client.pipeline(transaction=True)
    pipe.hset(session_key, "last_accessed", datetime.utcnow().isoformat())
    pipe.expire(session_key, SESSION_TTL)
    pipe.execute()
    user_data = json.loads(session_data.get("user_data", "{}"))
    return {
        "user_data": user_data,
        "created_at": session_data.get("created_at"),
        "last_accessed": session_data.get("last_accessed"),
    }


def destroy_session(session_id):
    """Delete a session from Redis."""
    if session_id:
        session_key = get_session_key(session_id)
        redis_client.delete(session_key)


def get_current_session():
    """Get the current session from the request cookie."""
    session_id = request.cookies.get(SESSION_COOKIE_NAME)
    return get_session(session_id), session_id


# --- Caching Decorator ---

CACHE_PREFIX = "cache:"
DEFAULT_CACHE_TTL = 300  # 5 minutes


def cache_key_for_function(func, args, kwargs):
    """Generate a deterministic cache key for a function call."""
    key_data = {
        "module": func.__module__,
        "qualname": func.__qualname__,
        "args": repr(args),
        "kwargs": repr(sorted(kwargs.items())),
    }
    key_string = json.dumps(key_data, sort_keys=True)
    key_hash = hashlib.sha256(key_string.encode()).hexdigest()
    return f"{CACHE_PREFIX}{func.__qualname__}:{key_hash}"


def redis_cache(ttl=DEFAULT_CACHE_TTL, key_prefix=None):
    """
    Caching decorator for expensive database queries.
    
    Usage:
        @redis_cache(ttl=600)
        def get_user_profile(user_id):
            # expensive database query
            ...
    
        @redis_cache(ttl=120, key_prefix="products")
        def get_product_list(category):
            # expensive database query
            ...
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            if key_prefix:
                # Allow custom key prefix for easier cache invalidation
                key_data = repr(args) + repr(sorted(kwargs.items()))
                key_hash = hashlib.sha256(key_data.encode()).hexdigest()
                cache_key = f"{CACHE_PREFIX}{key_prefix}:{key_hash}"
            else:
                cache_key = cache_key_for_function(func, args, kwargs)

            # Try to get from cache
            try:
                cached = redis_client.get(cache_key)
                if cached is not None:
                    result = json.loads(cached)
                    return result
            except (redis.RedisError, json.JSONDecodeError):
                # If Redis is down or data is corrupt, fall through to execute function
                pass

            # Execute the function
            result = func(*args, **kwargs)

            # Store in cache
            try:
                serialized = json.dumps(result)
                redis_client.setex(cache_key, ttl, serialized)
            except (redis.RedisError, TypeError):
                # If we can't cache, that's okay - just return the result
                pass

            return result

        # Attach cache management methods to the wrapper
        def invalidate(*args, **kwargs):
            """Invalidate the cache for specific arguments."""
            if key_prefix:
                key_data = repr(args) + repr(sorted(kwargs.items()))
                key_hash = hashlib.sha256(key_data.encode()).hexdigest()
                cache_key = f"{CACHE_PREFIX}{key_prefix}:{key_hash}"
            else:
                cache_key = cache_key_for_function(func, args, kwargs)
            redis_client.delete(cache_key)

        def invalidate_all():
            """Invalidate all cached results for this function or prefix."""
            pattern = f"{CACHE_PREFIX}{key_prefix or func.__qualname__}:*"
            cursor = 0
            while True:
                cursor, keys = redis_client.scan(cursor, match=pattern, count=100)
                if keys:
                    redis_client.delete(*keys)
                if cursor == 0:
                    break

        wrapper.invalidate = invalidate
        wrapper.invalidate_all = invalidate_all
        return wrapper
    return decorator


# --- Rate Limiting ---

RATE_LIMIT_PREFIX = "ratelimit:"


def is_rate_limited(identifier, max_requests=100, window_seconds=60):
    """
    Simple sliding window rate limiter using Redis.
    Returns (is_limited, remaining_requests, reset_time).
    """
    key = f"{RATE_LIMIT_PREFIX}{identifier}"
    now = time.time()
    window_start = now - window_seconds

    pipe = redis_client.pipeline(transaction=True)
    # Remove old entries outside the window
    pipe.zremrangebyscore(key, 0, window_start)
    # Count current requests in window
    pipe.zcard(key)
    # Add current request
    pipe.zadd(key, {f"{now}-{secrets.token_hex(4)}": now})
    # Set expiry on the key
    pipe.expire(key, window_seconds)
    results = pipe.execute()

    current_count = results[1]
    is_limited = current_count >= max_requests
    remaining = max(0, max_requests - current_count - 1) if not is_limited else 0

    return is_limited, remaining, window_seconds


