@app.before_request
def rate_limit_check():
    """Apply rate limiting before each request."""
    # Use IP address as identifier (in production, consider X-Forwarded-For behind proxy)
    client_ip = request.remote_addr
    is_limited, remaining, reset = is_rate_limited(client_ip, max_requests=100, window_seconds=60)

    if is_limited:
        response = jsonify({
            "error": "Rate limit exceeded",
            "message": "Too many requests. Please try again later.",
            "retry_after": reset,
        })
        response.status_code = 429
        response.headers["Retry-After"] = str(reset)
        response.headers["X-RateLimit-Remaining"] = "0"
        return response

    # Store remaining for use in after_request
    request.rate_limit_remaining = remaining


@app.after_request
def add_rate_limit_headers(response):
    """Add rate limit headers to all responses."""
    remaining = getattr(request, 'rate_limit_remaining', None)
    if remaining is not None:
        response.headers["X-RateLimit-Remaining"] = str(remaining)
    return response


