@app.route("/cache/invalidate", methods=["POST"])
def invalidate_cache():
    """Invalidate cache by prefix. Requires admin session."""
    session_data, _ = get_current_session()

    if not session_data or session_data["user_data"].get("role") != "admin":
        return jsonify({"error": "Admin access required"}), 403

    data = request.get_json()
    prefix = data.get("prefix") if data else None

    if prefix == "user_profile":
        get_user_from_database.invalidate_all()
    elif prefix == "products":
        get_products_from_database.invalidate_all()
    elif prefix == "stats":
        get_site_statistics.invalidate_all()
    elif prefix == "all":
        get_user_from_database.invalidate_all()
        get_products_from_database.invalidate_all()
        get_site_statistics.invalidate_all()
    else:
        return jsonify({
            "error": "Invalid prefix",
            "valid_prefixes": ["user_profile", "products", "stats", "all"],
        }), 400

    return jsonify({"message": f"Cache invalidated for prefix: {prefix}"})


@app.route("/sessions/active", methods=["GET"])
def active_sessions():
    """List active session count. Requires admin session."""
    session_data, _ = get_current_session()

    if not session_data or session_data["user_data"].get("role") != "admin":
        return jsonify({"error": "Admin access required"}), 403

    # Count session keys
    cursor = 0
